#!/usr/bin/env python3
"""
事件雷达 → 飞书推送
作为盘前流程的一环，扫描事件-持仓交叉结果并推送。
用法：python3 push_event_radar.py [--scan-file scan.json] [--webhook URL]
"""

from __future__ import annotations

import json
import sys
from datetime import datetime
from pathlib import Path

import requests

# ── 路径 ──────────────────────────────────────────────
QUANT_ROOT = Path(__file__).resolve().parents[1]
CACHE_DIR = QUANT_ROOT / "data" / "event_radar"

# ── Webhook ───────────────────────────────────────────
# 复用已有的投研推送 webhook
FEISHU_WEBHOOK = (
    "https://open.feishu.cn/open-apis/bot/v2/hook/"
    "f54d31a7-226d-4fac-aeaf-44b84c5c85b7"
)


def build_feishu_card(matches: list[dict], summary: dict) -> dict:
    """构建飞书消息卡片"""
    if not matches:
        return {
            "msg_type": "interactive",
            "card": {
                "header": {
                    "title": {"tag": "plain_text", "content": "📡 事件雷达 · 今日无持仓事件"},
                    "template": "wathet",
                },
                "elements": [
                    {
                        "tag": "div",
                        "text": {
                            "tag": "lark_md",
                            "content": "今日扫描未发现持仓相关事件。",
                        },
                    }
                ],
            },
        }

    # 按持仓分组
    by_code: dict[str, list[dict]] = {}
    for m in matches:
        code = m["ts_code"]
        if m["pool"] == "持仓":
            by_code.setdefault(code, []).append(m)

    elements = []

    # Header
    holding_hit = summary["holding_hit_count"]
    elements.append(
        {
            "tag": "div",
            "text": {
                "tag": "lark_md",
                "content": (
                    f"**持仓命中 {holding_hit} 只** · "
                    f"匹配 {summary['total_matches']} 条 · "
                    f"预期差 {summary['avg_expectation']}"
                ),
            },
        }
    )
    elements.append({"tag": "hr"})

    # 逐只股票展示
    for code, evs in sorted(by_code.items()):
        name = evs[0]["stock_name"]
        count = len(evs)
        elements.append(
            {
                "tag": "div",
                "text": {
                    "tag": "lark_md",
                    "content": f"**{code} {name}** ({count}条)",
                },
            }
        )

        for ev in sorted(
            evs, key=lambda x: abs(x["expectation_score"]), reverse=True
        )[:3]:  # 最多展示 3 条
            score = ev["expectation_score"]
            direction = "🟢" if score > 0 else "🔴" if score < -0.3 else "🟡"
            rel = ev["relation_type"]
            reason = ev["relation_reason"]
            if len(reason) > 100:
                reason = reason[:100] + "…"

            elements.append(
                {
                    "tag": "div",
                    "text": {
                        "tag": "lark_md",
                        "content": (
                            f"{direction} [{ev['event_type_display']}] "
                            f"{ev['event_title'][:60]}\n"
                            f" 关联: {rel} · {reason}"
                        ),
                    },
                }
            )
        elements.append({"tag": "hr"})

    # Footer
    elements.append(
        {
            "tag": "note",
            "elements": [
                {
                    "tag": "plain_text",
                    "content": f"事件雷达 · {datetime.now():%m-%d %H:%M} · stocks.matraceai.com",
                }
            ],
        }
    )

    return {
        "msg_type": "interactive",
        "card": {
            "header": {
                "title": {
                    "tag": "plain_text",
                    "content": f"📡 事件雷达 · {holding_hit}只持仓相关",
                },
                "template": "wathet",
            },
            "elements": elements,
        },
    }


def main():
    # 找最新扫描结果
    scan_files = sorted(CACHE_DIR.glob("scan_*.json"), reverse=True)
    if not scan_files:
        print("无扫描结果", file=sys.stderr)
        sys.exit(1)

    with open(scan_files[0]) as f:
        data = json.load(f)

    matches = data.get("matches", [])
    summary = data.get("summary", {})

    print(
        f"[event_radar_push] {len(matches)} 条匹配 | "
        f"持仓命中: {summary.get('holding_hit_count', 0)}",
        file=sys.stderr,
    )

    # 只在有持仓命中时推送
    if summary.get("holding_hit_count", 0) == 0:
        print("[event_radar_push] 无持仓命中，跳过推送", file=sys.stderr)
        return

    card = build_feishu_card(matches, summary)

    try:
        resp = requests.post(FEISHU_WEBHOOK, json=card, timeout=10)
        resp.raise_for_status()
        print("[event_radar_push] ✅ 推送成功", file=sys.stderr)
    except Exception as e:
        print(f"[event_radar_push] ❌ 推送失败: {e}", file=sys.stderr)


if __name__ == "__main__":
    main()

