# 快速分析：只用 4/23-4/29 的事件
python3 << 'PY'
import requests, time, json
from datetime import datetime, date
from collections import defaultdict
import numpy as np

API = "https://stocks.matraceai.com"
# 拉更多页，取 4/23-4/29 交易日的事件
all_events = []
for page in range(1, 26):
    try:
        resp = requests.get(f"{API}/api/events/?page={page}", timeout=10)
        data = resp.json()
        results = data.get("results", [])
        if not results:
            break
        all_events.extend(results)
        if len(results) < 20:
            break
    except:
        break
    time.sleep(0.2)

# 过滤：只在交易日（4/23-4/30 中排除周末）
trading_days_0423_0430 = [
    date(2026,4,23), date(2026,4,24),  # Thu, Fri
    date(2026,4,27), date(2026,4,28), date(2026,4,29), date(2026,4,30),  # Mon-Thu
]

events_filtered = []
for ev in all_events:
    try:
        ev_date = datetime.strptime(ev["published_at"][:10], "%Y-%m-%d").date()
    except:
        continue
    if date(2026,4,23) <= ev_date <= date(2026,4,29):
        events_filtered.append(ev)

print(f"全量事件: {len(all_events)}")
print(f"4/23-4/29 事件: {len(events_filtered)}")
print(f"日期分布: ", end="")
from collections import Counter
dc = Counter()
for ev in events_filtered:
    dc[ev["published_at"][:10]] += 1
for d, c in sorted(dc.items()):
    print(f"{d}:{c} ", end="")
print()

# 获取价格数据（从腾讯接口）
def get_stock_price(ts_code, target_date_str):
    """获取指定日期的收盘价"""
    if ts_code.endswith(".SH"):
        qq = f"sh{ts_code[:6]}"
    elif ts_code.endswith(".SZ"):
        qq = f"sz{ts_code[:6]}"
    else:
        return None

    target_dt = datetime.strptime(target_date_str, "%Y-%m-%d").date()

    try:
        url = f"https://web.ifzq.gtimg.cn/appstock/app/fqkline/get?param={qq},day,,,30,qfq"
        resp = requests.get(url, timeout=10, headers={"Referer":"https://gu.qq.com/"})
        data = resp.json()
        stock_data = data.get("data", {}).get(qq, {})
        klines = stock_data.get("day") or stock_data.get("qfqday", [])

        price_map = {}
        for k in klines:
            if len(k) < 3:
                continue
            try:
                d = datetime.strptime(k[0], "%Y-%m-%d").date()
                price_map[d] = float(k[2])
            except:
                continue

        # 找 <= target 的最近交易日
        dates = sorted(price_map.keys())
        for d in dates:
            if d <= target_dt:
                event_price = price_map[d]

        # 找 > target 的下一天
        next_price = None
        for d in dates:
            if d > target_dt:
                next_price = price_map[d]
                break

        return {"event_price": None, "next_price": None}
    except:
        return None

# 更简单的方法：直接批量查
# 建立价格缓存
price_cache = {}

def get_price(ts_code, dt):
    if ts_code.endswith(".SH"):
        qq = f"sh{ts_code[:6]}"
    else:
        qq = f"sz{ts_code[:6]}"

    key = qq
    if key not in price_cache:
        try:
            url = f"https://web.ifzq.gtimg.cn/appstock/app/fqkline/get?param={qq},day,,,30,qfq"
            resp = requests.get(url, timeout=10, headers={"Referer":"https://gu.qq.com/"})
            data = resp.json()
            stock_data = data.get("data", {}).get(qq, {})
            klines = stock_data.get("day") or stock_data.get("qfqday", [])
            price_cache[key] = {}
            for k in klines:
                if len(k) < 3: continue
                try:
                    price_cache[key][datetime.strptime(k[0], "%Y-%m-%d").date()] = float(k[2])
                except: pass
        except:
            price_cache[key] = {}

    dates = sorted(price_cache[key].keys())
    if not dates:
        return None, None

    # 事件日价格（<= 事件日最近交易日）
    ev_price = None
    for d in dates:
        if d <= dt:
            ev_price = price_cache[key][d]

    # 事件后价格（事件日之后的下一个交易日）
    fwd_price = None
    for d in dates:
        if d > dt:
            fwd_price = price_cache[key][d]
            break

    return ev_price, fwd_price

# 分析
results = []
for ev in events_filtered:
    ev_date = datetime.strptime(ev["published_at"][:10], "%Y-%m-%d").date()
    exp_score = ev["expectation_score"]

    # 跳过中性
    if -0.05 <= exp_score <= 0.05:
        continue

    predicted_up = exp_score > 0

    for stock in ev.get("stocks", []):
        if stock.get("relevance_score", 0) < 0.6:
            continue

        ts_code = stock["ts_code"]
        ev_price, fwd_price = get_price(ts_code, ev_date)

        if ev_price is None or fwd_price is None:
            continue

        chg = (fwd_price - ev_price) / ev_price
        actual_up = chg > 0
        correct = (predicted_up and actual_up) or (not predicted_up and not actual_up)

        results.append({
            "date": ev_date.strftime("%Y-%m-%d"),
            "ts_code": ts_code,
            "name": stock.get("name", ""),
            "event": ev["title"][:60],
            "exp_score": exp_score,
            "relevance": stock["relevance_score"],
            "predicted": "UP" if predicted_up else "DOWN",
            "change_pct": round(chg*100, 2),
            "correct": correct,
        })

print(f"\n有效样本: {len(results)}")

if results:
    total = len(results)
    correct = sum(1 for r in results if r["correct"])
    hit_rate = correct / total * 100

    up_results = [r for r in results if r["predicted"] == "UP"]
    down_results = [r for r in results if r["predicted"] == "DOWN"]

    up_correct = sum(1 for r in up_results if r["correct"])
    down_correct = sum(1 for r in down_results if r["correct"])

    up_hit = up_correct / len(up_results) * 100 if up_results else 0
    down_hit = down_correct / len(down_results) * 100 if down_results else 0

    up_avg = np.mean([r["change_pct"] for r in up_results]) if up_results else 0
    down_avg = np.mean([r["change_pct"] for r in down_results]) if down_results else 0

    print(f"""
📊 事件信号验证结果
{'='*40}
样本量: {total}
命中率: {correct}/{total} = {hit_rate:.1f}%

看涨信号: {len(up_results)} 条, 命中 {up_hit:.1f}%, 平均涨跌 {up_avg:+.2f}%
看跌信号: {len(down_results)} 条, 命中 {down_hit:.1f}%, 平均涨跌 {down_avg:+.2f}%

方向准确率: {'✅ 有预测力' if hit_rate >= 55 else '⚠️ 微弱' if hit_rate >= 48 else '❌ 无预测力'}

Top 10 正确预测:
""")
    for r in sorted([r for r in results if r["correct"]], key=lambda x: abs(x["change_pct"]), reverse=True)[:10]:
        print(f"  {r['date']} {r['ts_code']:12s} {r['name']:8s} {r['predicted']:5s} {r['change_pct']:+6.2f}%  {r['event'][:40]}")

    print(f"\nTop 10 错误预测:")
    for r in sorted([r for r in results if not r["correct"]], key=lambda x: abs(x["change_pct"]), reverse=True)[:10]:
        print(f"  {r['date']} {r['ts_code']:12s} {r['name']:8s} {r['predicted']:5s} {r['change_pct']:+6.2f}%  {r['event'][:40]}")
else:
    print("无有效样本")
